// Keyword sets to search — rotate or run all
// Bundesagentur API: https://api.arbeitsagentur.de/prod/jobboerse/jobsuche-service/pc/v4/jobs
const searches = [
  { keywords: 'Software Developer', location: '', radius: 200, lang: 'Englisch' },
  { keywords: 'Frontend Developer', location: '', radius: 200, lang: 'Englisch' },
  { keywords: 'Backend Developer',  location: '', radius: 200, lang: 'Englisch' },
  { keywords: 'Data Analyst',       location: '', radius: 200, lang: 'Englisch' },
  { keywords: 'IT Support',         location: '', radius: 200, lang: 'Englisch' },
  { keywords: 'Buchhalter',         location: '', radius: 200, lang: '' },
  { keywords: 'Pflegefachkraft',    location: '', radius: 200, lang: '' },
  { keywords: 'Fahrer',             location: '', radius: 200, lang: '' }
];
return searches.map(s => ({ json: s }));

// Extract and clean job listings
const raw = $input.first().json;
const jobs = raw.stellenangebote || [];

const clean = jobs.slice(0, 10).map(j => ({
  id:          j.refnr || '',
  title:       j.titel || '',
  employer:    j.arbeitgeber || '',
  location:    j.arbeitsort?.ort || '',
  region:      j.arbeitsort?.region || '',
  posted:      j.eintrittsdatum || '',
  url:         `https://www.arbeitsagentur.de/jobsuche/jobdetail/${j.refnr}`,
  remote:      j.fuerFluechtlingeGeeignet || false,
  fulltime:    j.arbeitszeitmodelle?.includes('vz') || false,
  source:      'Bundesagentur'
}));

return clean.map(j => ({ json: j }));

// Format job for Telegram channel post
const j = $input.first().json;

const emoji = j.title.toLowerCase().includes('developer') || j.title.toLowerCase().includes('engineer') ? '💻' :
              j.title.toLowerCase().includes('pflege') ? '🏥' :
              j.title.toLowerCase().includes('fahrer') ? '🚗' : '💼';

const location = j.location ? `📍 ${j.location}${j.region ? ', ' + j.region : ''}` : '📍 Deutschland';
const time = j.fulltime ? '⏰ Vollzeit' : '⏰ Teilzeit/flexibel';

const text = `${emoji} *${j.title}*
🏢 ${j.employer}
${location}
${time}

🔗 [Открыть вакансию](${j.url})
📄 [Сделать Bewerbung](https://t.me/BewerbZenBot)`;

return [{ json: { text, jobId: j.id, title: j.title } }];
